import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {'61': {'1': '<p>The anointed speaker — whose identity the chapter leaves implicit but whose profile matches the Servant (42:1-4, 49:1-6) — opens with a dual claim: the Spirit of YHWH (<em>ruach</em>, disp 4) rests upon him, and YHWH has anointed (<em>mashach</em>) him. The Spirit-anointing is the same bestowal promised for the ideal king (11:2) and the Servant (42:1). His commission is entirely oriented to the broken: bring good news to the afflicted, bind up the brokenhearted, proclaim release to captives, opening to those who are bound. Jesus reads this verse aloud in the Nazareth synagogue and declares it fulfilled in his hearing (Luke 4:18-19), making the Isaianic commission the self-definition of his own ministry.</p>', '2': "<p>The anointed one proclaims the year of YHWH's favor (<em>ratson</em> — acceptance/delight) and the day of vengeance of our God (<em>elohim</em>, disp 4) — the same pair as 34:8 and 63:4. YHWH's favor and YHWH's vengeance are not opposites but two dimensions of his covenant faithfulness: favor to the afflicted, vengeance on the oppressor. Jesus stops his quotation in Luke 4:19 before the day of vengeance — reading the first advent as the year of favor, and leaving the day of vengeance for the end. The divine name <em>YHWH</em> (disp 4) appears three times in vv 1-3, anchoring the commission in covenant identity.</p>", '3': "<p>The anointed one comes to bestow — the Hebrew verb (<em>sum</em>, to set/place) is gift-language. Three reversals: garland instead of ashes, oil of joy instead of mourning, garment of praise instead of faint spirit. The recipients will be called oaks of righteousness (<em>tsedaqah</em>), planted by YHWH for his glory (<em>kabod</em>). The Spirit (<em>ruach</em>, disp 4) of faintness is displaced by the garment of praise — the same Spirit that anoints the speaker (v 1) also transforms the mourners. <em>Tsedaqah</em> is the character of the community, not merely a legal verdict; they become what YHWH's righteousness creates.</p>", '4': "<p>The restored community rebuilds the ancient ruins (<em>olam</em>-desolations, disp 3) — the same vocabulary as 44:26, 49:8, 58:12. The olam-desolations are the cities ruined since antiquity; the restored community will inhabit what was long abandoned. The task of rebuilding is both literal (returning exiles reconstructing Judean cities) and symbolic (the reconstitution of the covenant community's social fabric). The time-depth of <em>olam</em> signals that what is being restored is not merely the pre-exile state but the original covenant design.</p>", '5': '<p>Strangers and foreigners will serve as agricultural workers — the economic reversal of exile, where Israel served foreign powers. The restored community does not do menial labor for others; others serve them. This is the eschatological inversion of Deut 28:43-44 (where the curse brought foreign domination). The restoration enacts the blessing-side of the covenant.</p>', '6': "<p>You will be called Priests of YHWH and Ministers of our God (<em>elohim</em>, disp 4; <em>YHWH</em>, disp 4). The entire restored community receives priestly designation — the extension of the Sinai promise (Exod 19:6: a kingdom of priests) to the whole people. They will eat the wealth of the nations and <em>kabod</em> (glory, disp 2) will be their boast. The glory previously stripped in exile is restored, but it is no longer self-generated prestige but the reflected <em>kabod</em> of YHWH's priests.</p>", '7': "<p>Instead of shame, double portion; instead of dishonor, rejoicing in inheritance. The double-portion language echoes the firstborn's rights (Deut 21:17) and Job's restoration (Job 42:10). Everlasting (<em>olam</em>, disp 3) joy will be theirs. The <em>olam</em>-joy is the characteristic mark of the restored community (35:10, 51:11) — not temporary relief but the permanent orientation of those who live in YHWH's favor.</p>", '8': "<p>YHWH grounds the promise in his own character: I, YHWH (disp 4), love justice (<em>mishpat</em>) and hate robbery and wrongdoing. His faithfulness (<em>emet</em>, truth/faithfulness, disp 2) is the measure of his reward: he will faithfully give what he has promised. He will make an everlasting covenant (<em>berit olam</em>, <em>berit</em> disp 3, <em>olam</em> disp 3) with them — the same covenant of 55:3, the Davidic <em>hesed</em> democratized to the whole community. The covenant rests entirely on YHWH's character, not on the community's performance.</p>", '9': "<p>Their descendants will be known (<em>yada</em>, disp 2) among the nations — the same knowing-by-act pattern as the exodus (Exod 14:4). YHWH's work in the community is itself the testimony to the nations. All who see them will acknowledge that they are a people YHWH (<em>YHWH</em>, disp 4) has blessed — the community's flourishing is a visible sign of YHWH's covenant faithfulness.</p>", '10': '<p>The speaker now rejoices in first person: I will greatly rejoice in YHWH (<em>YHWH</em>, disp 4); my <em>nefesh</em> (soul, disp 3) will exult in my God (<em>elohim</em>, disp 4). The <em>nefesh</em> — the whole self — is the seat of this exultation, not merely emotions. YHWH has clothed him with garments of salvation and wrapped him in a robe of <em>tsedaqah</em> (righteousness, disp 3) — the Servant/anointed figure himself is clothed in what he bestows on others (garland, oil, garment of vv 3 and 10). The bridegroom-bride image: as a bridegroom ornaments himself, as a bride adorns herself with jewels. The restoration is a wedding.</p>', '11': "<p>As the earth brings forth its sprouts and a garden makes its planting spring up, so the Lord GOD will cause righteousness (<em>tsedaqah</em>) and praise to spring up before all nations. The seed-to-sprout image is YHWH's sovereignty over growth: what he plants will come up, what he causes to spring up is both <em>tsedaqah</em> and the praise of nations. The organic metaphor is the same as 55:10-11 — YHWH's word achieves its purpose as surely as rain produces crops. The final chapter of Isaiah's first major movement ends with <em>tsedaqah</em> and praise visible to all nations — the full scope of the commission from v 1.</p>"}, '62': {'1': "<p>The speaker — YHWH or the anointed one of chapter 61 — will not be silent until Zion's righteousness (<em>tsedaqah</em>) shines like the dawn and her salvation burns like a torch. The intercessory silence-refused is the inverse of Jerusalem's commanded silence-refused watchmen (v 6): both the divine advocate and the human watchers refuse to rest until Zion is restored. The until-structure frames the entire chapter: the goal is Zion's vindication before all nations (v 2).</p>", '2': "<p>The nations will see your righteousness (<em>tsedaqah</em>) and all kings your glory (<em>kabod</em>, disp 2). You will be called by a new name that YHWH (<em>YHWH</em>, disp 4) himself will give. The new name signals transformed identity — the same as the renamed cities of 1:26 and the new name of the servant in 62:4. A name given by YHWH is a name that reveals what YHWH declares to be true about the bearer. <em>Melek</em>/king (disp 2): all kings see Zion's glory, marking the universal scope of the restoration.</p>", '3': "<p>Zion will be a crown of beauty in the hand of YHWH (<em>YHWH</em>, disp 4) and a royal diadem in the hand of her God (<em>elohim</em>, disp 4). The crown/diadem is not worn by YHWH but held in his hand — Zion is YHWH's prize, the proof of his sovereign beauty, displayed to all. The image reverses the exile's shame: the abandoned city becomes the treasured gem.</p>", '4': "<p>The old names — Forsaken and Desolate — are replaced by new covenant names: My Delight Is in Her (<em>Hephzibah</em>) and Married (<em>Beulah</em>). YHWH (<em>YHWH</em>, disp 4) will delight in Zion and the land will be married. The marriage metaphor resumes from 54:4-6: the widowed city is re-espoused. The name-change is simultaneously an ontological declaration — YHWH's naming constitutes the reality he names.</p>", '5': "<p>As a young man marries a young woman, your sons will marry you — the sons of Zion become her bridegrooms, the restored community re-inhabiting and re-constituting the city. As a bridegroom rejoices over his bride, so God (<em>elohim</em>, disp 4) will rejoice over you. The divine joy mirrors the human joy of a wedding — YHWH's restoration of Zion is not grudging or reluctant but celebratory.</p>", '6': '<p>I have stationed watchmen on your walls who will never be silent day or night. Those who remind YHWH (<em>YHWH</em>, disp 4) of his promises (<em>mazkire YHWH</em> — those who call YHWH to remembrance) are given no rest. The watchmen and the YHWH-reminders form an unbroken intercession. The logic: because YHWH has sworn (v 8), the petitioners press YHWH on the basis of his own oath. This is the prayer-theology of covenant: reminding God of his promises is not impertinence but the right use of covenant relationship.</p>', '7': "<p>Give him no rest until he establishes Jerusalem and makes her a glory (<em>tehillah</em>) in the earth. The until-structure of v 1 now applies to the intercessors: like the speaker (v 1), the watchmen refuse rest until the goal is achieved. The goal is not merely Zion's safety but her praise-worthiness before the earth.</p>", '8': "<p>YHWH has sworn by his right hand and by his strong arm — a double oath-formula. Never again will he give grain and wine to enemies as food and drink. The oath grounds the community's confidence: YHWH's oath is as reliable as his own arm, the same arm that brought salvation (51:5, 52:10, 53:1). The <em>YHWH</em> (disp 4) who swears is the covenant LORD whose oaths are as permanent as the Noah covenant (54:9).</p>", '9': '<p>Those who harvest will eat and praise YHWH (<em>YHWH</em>, disp 4); those who gather the vintage will drink it in the courts of my holiness (<em>qodesh</em>, disp 2). The harvest and vintage are consumed in sacred space — the restored economy is inseparable from worship. The courts of my holiness (<em>hatsrot qodshi</em>) signals that the temple is rebuilt and functioning, and the produce of the land is offered there as first-fruits before being enjoyed.</p>', '10': '<p>Pass through the gates; prepare the way for the people; build the highway; clear it of stones; raise a signal banner. The highway-preparation echoes 40:3 (prepare in the wilderness a highway for YHWH) and 57:14 — but here it is addressed to those within Zion who must open the gates for the returning exiles. The banner (<em>nes</em>) is the rally-signal for the scattered nations (11:10-12). The command is urgent: the return is imminent.</p>', '11': '<p>YHWH (<em>YHWH</em>, disp 4) has declared to the ends of the earth: Say to daughter Zion, Your salvation is coming. The salvation and its reward come with the returning YHWH — salvation is personified as a figure who brings his recompense. This language anticipates Rev 22:12 (I am coming, and my reward is with me).</p>', '12': "<p>They will be called the Holy People (<em>qodesh</em>, disp 2), the Redeemed of YHWH (<em>YHWH</em>, disp 4); Zion will be named Sought Out, A City Not Forsaken. The <em>qodesh</em>/holy name applied to the people is the same holiness-designation given to YHWH's arm (52:10) and his courts (62:9) — the community shares in the holiness of YHWH. The new name reverses the exile-name Forsaken (v 4): the city that was abandoned is now permanently sought.</p>"}, '63': {'1': '<p>A dramatic theophany: the divine warrior returns from Edom in blood-red garments, striding in his greatness, declaring his own righteousness (<em>tsedaqah</em>, disp 3) and his great power of salvation. The question-and-answer dialogue (Who is this? — I, speaking in righteousness) is a covenant-court exchange. The red garments of the warrior anticipate the winepress image of vv 2-3. <em>Tsedaqah</em> is simultaneously the character of the warrior and the verdict he enacts — his victory is righteous because it restores right order.</p>', '2': "<p>The garments reddened as from a winepress provoke the question. The winepress-treading is both literal (the harvested grapes) and metaphorical (the trampling of nations in judgment). The image recurs in Rev 19:15, where the rider on the white horse treads the winepress of YHWH's wrath — the same divine warrior identified with the returning Messiah.</p>", '3': "<p>YHWH declares: I trod the winepress alone — from the nations no one helped me. The aloneness echoes the Servant's isolation in 53:3-6. I trod them in my anger and trampled them in my fury; their blood spattered on my garments. The judicial violence is YHWH's own act, unassisted, against the nations that oppressed his people. The fury is covenant anger — the wrath of one who has been rejected in covenant.</p>", '4': '<p>The day of vengeance was in my heart, and the year of my redemption had arrived — the same paired terms as 61:2, but now enacted. The day of vengeance in the heart of God: YHWH did not act impulsively but at the determined moment. The year of redemption is the same <em>ratson</em>-year of 61:2 — the two are inseparable: favor to the afflicted and vengeance on the oppressor happen simultaneously.</p>', '5': "<p>YHWH looked and there was no one to help — the same astonishment as 59:16, where no one intervened and YHWH's own arm brought salvation. I was appalled that there was none to sustain me; so my own arm brought salvation and my fury upheld me. The divine self-sufficiency in redemption is total: YHWH does not partner with human power. The arm of YHWH is the repeated image of the whole of Isaiah 40-66.</p>", '6': '<p>I trampled the peoples in my anger, made them drunk in my fury, and poured their blood down to the ground. The intoxication-image (cf. 51:17-23: the cup of wrath) is now given to the oppressor-nations. What Zion drank in judgment, YHWH now forces on those who tormented Zion. The cosmic justice is complete: the one who handed out the cup of wrath now drains it himself as the oppressor.</p>', '7': "<p>The hymn of YHWH's lovingkindnesses (<em>hesed</em>, disp 4) — the speaker now turns from the theophany to recount YHWH's past faithfulness. The plural <em>hasde YHWH</em> (lovingkindnesses of YHWH, disp 4) emphasizes the accumulation of covenant-faithful acts over Israel's history. All that YHWH has bestowed on Israel, the great goodness according to his compassion and <em>hesed</em> (disp 4) — the double <em>hesed</em> at the opening of the hymn establishes that YHWH's character is the ground of his acts. The <em>YHWH</em> (disp 4) repeated three times in this verse underscores that this is personal-covenant love, not abstract divine benevolence.</p>", '8': "<p>YHWH said: Surely they are my people, children who will not prove false — and so he became their Savior. The divine self-commitment to Israel is based on what YHWH declared, not on what Israel delivered. The false-not-proving is what YHWH hoped for; what he received instead is the subject of vv 9-10. But the Savior-relationship was constituted by the declaration, not revoked by Israel's subsequent unfaithfulness.</p>", '9': "<p>In all their affliction he was afflicted (<em>tsar lo</em>) — the divine solidarity with Israel's suffering. The angel of his presence (<em>phanaw</em> — face) saved them. In his love (<em>ahav</em>) and compassion (<em>hemlah</em>) he redeemed them; he lifted them and carried them all the ancient days (<em>kol yeme olam</em>, disp 3). The carrying-image echoes 40:11 (shepherd carrying lambs) and 46:3-4 (YHWH carrying Israel from birth). The <em>olam</em>-carrying is not a moment but a sustained history of divine solidarity.</p>", '10': "<p>But they rebelled and grieved his Holy Spirit (<em>ruach qodesh</em>, <em>ruach</em> disp 4, <em>qodesh</em> disp 2) — the first occurrence of the exact phrase Holy Spirit in the Hebrew Bible (occurring here and v 11). The rebellion turned YHWH against them as their enemy. Grieving the Spirit is the language Paul uses in Eph 4:30 — the same theological category applied to the covenant community's relation to the divine presence. The Holy Spirit was the gift of YHWH's indwelling; its grieving is the rupture of intimacy.</p>", '11': '<p>Then he remembered the ancient days, the time of Moses and his people. Where is the one who brought them up from the sea with the shepherds of his flock? Where is the one who put his Holy Spirit (<em>ruach qodesh</em>, <em>ruach</em> disp 4, <em>qodesh</em> disp 2) among them? The prayer invokes the exodus precedent: YHWH who was with Moses and Israel in the wilderness is the same YHWH now. The Holy Spirit placed among the exodus community is the model for the Spirit-presence that vv 14 and 61:1-3 promise. The remembering of YHWH (<em>olam</em> days, disp 3) is the basis for petitioning a new exodus.</p>', '12': "<p>Who led Moses by the right hand with his glorious arm, dividing the waters before them to make himself an everlasting (<em>olam</em>, disp 3) name — the exodus as the paradigmatic name-making event of YHWH. The <em>olam</em>-name is what YHWH's self-revelation in the exodus established permanently. The prayer is: do again what made your name everlasting.</p>", '13': '<p>Who led them through the depths — like a horse in the desert, they did not stumble. The comparison of Israel-in-the-Red-Sea to a horse in open terrain: in a place of maximum danger (the depths), Israel moved with maximum freedom (no stumbling). The God who made a safe path through the sea can make a safe path through any terrain.</p>', '14': "<p>As cattle descend into a valley to rest, the Spirit of YHWH (<em>ruach YHWH</em>, <em>ruach</em> disp 4, <em>YHWH</em> disp 4) gave them rest. The Spirit that grieved in v 10 is the same Spirit that gave rest in the wilderness — the contrast is intentional. YHWH led his people through the wilderness by his Spirit to make himself a glorious (<em>kabod</em>) name. The prayer ground: you have done this before for your own name's sake; do it again.</p>", '15': "<p>Look down from heaven and see, from your holy (<em>qodesh</em>, disp 2) and glorious dwelling. Where are your zeal and your strength? The yearning of your heart and your compassion — are they withheld from me? The prayer invokes YHWH's holy dwelling only to lament that what comes from that dwelling — zeal, strength, compassion — seems absent. This is the lament-form of covenant prayer: calling YHWH to act in accordance with what he is.</p>", '16': "<p>You are our Father (<em>av</em>) — though Abraham does not know us and Israel does not acknowledge us; you, YHWH (<em>YHWH</em>, disp 4), are our Father; our Redeemer from of old (<em>olam</em>, disp 3) is your name. The appeal to divine fatherhood over ancestral fatherhood: even if the patriarchs are inaccessible (in death), YHWH's fatherhood is present and active. The <em>olam</em>-Redeemer: YHWH's redemptive character is not a new decision but his eternal name — what he has always been called.</p>", '17': '<p>YHWH, why do you let us stray from your ways and harden our hearts from fearing you? The boldness of the question: the community holds YHWH partially responsible for their own waywardness — not as an excuse but as a cry for the return of his sustaining grace. Turn back for the sake of your servants, the tribes of your inheritance. The servants and the tribal inheritance are the covenant vocabulary that grounds the petition.</p>', '18': "<p>Your holy people (<em>qodesh</em>, disp 2) possessed your sanctuary for a little while; now our adversaries have trampled it down. The brevity of the possession (a little while) is measured against the eternity of YHWH's <em>olam</em>-name (v 16). The trampled sanctuary is the specific wound that makes the prayer urgent. YHWH's holiness-designation for Israel and the temple that housed his holiness are both violated.</p>", '19': '<p>We have become like those you never ruled, like those who were never called by your name. The ultimate covenant-desolation: to be indistinguishable from those outside the covenant. The prayer is at its lowest point here, which prepares the way for the breakthrough petition of chapter 64: the tearing-open of the heavens.</p>'}, '64': {'1': "<p>Oh, that you would tear open the heavens and come down — the climax of the lament that began at 63:7. The tearing-open is a plea for theophany more dramatic than Sinai: mountains quaking at YHWH's presence. The mountains quaking at YHWH's coming recurs in Mic 1:4, Nah 1:5, and Hab 3:6 — it is the standard register for YHWH's war-presence. The prayer is for YHWH to make his nearness unmistakable and terrifying.</p>", '2': "<p>As when fire kindles brushwood and water boils — to make your name known (<em>yada</em>, disp 2) to your enemies, so that the nations would tremble at your presence. The fire-water images are Sinai and the Red Sea: YHWH's fire on the mountain and his control of water in the exodus. The prayer names both as the precedent for the present petition. The goal is not destruction for its own sake but the knowing of YHWH's name by the nations — the same goal as the exodus (Exod 9:16).</p>", '3': "<p>When you did awe-inspiring things we did not expect, you came down — the mountains quaked at your presence. The Sinai theophany is the paradigm case: Israel did not request or anticipate YHWH's self-disclosure in smoke and fire and earthquake. The awe-inspiring-things-we-did-not-expect pattern establishes that YHWH's greatest acts exceed human prediction.</p>", '4': "<p>From of old (<em>olam</em>, disp 3) no one has heard, no ear has perceived, no eye has seen any God besides you, who acts on behalf of those who wait for him. The incomparability of YHWH: no other god acts for those who wait. This verse is quoted in 1 Cor 2:9 as the pattern of what the Spirit reveals — what eye has not seen, ear has not heard. The scope of YHWH's acting for-those-who-wait goes beyond what natural perception can anticipate, which is why the Spirit must reveal it.</p>", '5': "<p>You come to the aid of those who joyfully do right, those who remember you in your ways. But you were angry, and we sinned; in these ways we were and have been for a long time (<em>olam</em>, disp 3). The confession is embedded in the acknowledgment of YHWH's prior faithfulness: YHWH aids those who do right, but we have not done right. The <em>olam</em>-sinning (sinning for a long time) makes the confession generational, not merely personal.</p>", '6': "<p>We have all become like one who is unclean; all our righteous deeds (<em>tsedaqot</em>, <em>tsedaqah</em> disp 3) are like a filthy rag; we all wither like a leaf, and our iniquities, like the wind, carry us away. The most explicit confession in the Isaiah corpus: even the community's <em>tsedaqah</em>-acts are contaminated. The filthy-rag image is deliberately shocking — the very acts that should commend them to YHWH are themselves impure. The <em>ruach</em> (wind/spirit, disp 4) that carries them away here is not the Spirit of YHWH but their own iniquities functioning as a wind — the inversion of the Spirit who guided Israel (63:14).</p>", '7': '<p>There is no one who calls on your name, who stirs himself to take hold of you; for you have hidden your face from us and delivered us into the hand of our iniquity. The mutual abandonment: no one seeks YHWH; YHWH has hidden his face. The hidden-face is the covenant curse (Deut 31:17-18; Ps 88:14). But the phrase delivered us into the hand of our iniquity makes iniquity itself the captor — a striking personification. Sin is not just a wrong act but a power that holds.</p>', '8': "<p>But now, YHWH (<em>YHWH</em>, disp 4), you are our Father; we are the clay, and you are our potter; we are all the work of your hands. The potter-clay image (Jer 18:1-10; Rom 9:20-21) asserts that the relationship between YHWH and Israel is not a covenant of equals but of creator and creature — which is precisely why the community can appeal to YHWH's creative sovereignty to reconstitute them. The appeal is: since you made us, you can remake us.</p>", '9': "<p>Do not be exceedingly angry, YHWH (<em>YHWH</em>, disp 4); do not remember iniquity forever. Please look — we are all your people. The petition invokes covenant identity: your people. The not-remembering-iniquity-forever appeal to YHWH's own promise: 43:25 (I am the one who blots out your transgressions for my own sake and will not remember your sins).</p>", '10': "<p>Your holy (<em>qodesh</em>, disp 2) cities have become a wasteland; Zion is a wilderness, Jerusalem a desolation. The triple description of destruction — wasteland, wilderness, desolation — grounds the prayer in the concrete reality of exile. The holy cities (plural) include not only Jerusalem but the towns of Judah, all designated as YHWH's sacred precincts that have been violated.</p>", '11': "<p>Our holy (<em>qodesh</em>, disp 2) and glorious house where our fathers praised you has been burned with fire, and all our cherished places have become ruins. The temple's destruction is the focal point of the lament: the house built for YHWH's glory (<em>kabod</em>) is ash. The loss is not merely structural but theological — the place of YHWH's dwelling on earth is gone. Will you hold yourself back (v 12)?</p>", '12': "<p>Will you hold yourself back for all this, YHWH (<em>YHWH</em>, disp 4)? Will you keep silent while you afflict us so grievously? The final petition is purely interrogative — the prayer ends not with confident declaration but with pressing the question. The silence of YHWH in the face of Zion's ruin is itself the thing being challenged. The chapter that began with the tearing of the heavens ends with the question of whether YHWH will remain silent — which sets up chapter 65's answer: YHWH has not been silent; Israel has not listened.</p>"}, '65': {'1': "<p>YHWH answers the prayer of 63:15-64:12 with a reversal: I let myself be sought by those who did not ask for me; I let myself be found by those who did not seek me. The divine passive — YHWH making himself available — precedes any human search. The declaration to those who did not ask is the pattern of pure grace: YHWH's initiative is prior to and not conditioned by human seeking. Paul quotes this verse in Rom 10:20 as the pattern of Gentile reception of the gospel — those who were not seeking YHWH found him.</p>", '2': '<p>All day long I spread out my hands to a rebellious people — the divine posture of invitation persistently rejected. The spread-out hands are both welcome (come to me) and lamentation (look at what you are doing). The description of the rebellious: walking in ways not good, following their own schemes — not ignorance but willful self-direction away from YHWH.</p>', '3': "<p>A people who continually provoke me to my face — the challenge is not covert but overt, in YHWH's direct sight. The specific provocations: sacrificing in gardens and burning incense on brick altars. These are the syncretistic practices of those who blend YHWH-worship with Canaanite and Babylonian fertility-cult. The provocation is intensified by its being in YHWH's face — shameless, not hidden.</p>", '4': '<p>Who sit among the graves — necromantic practice, seeking guidance from the dead (cf. 8:19). Who eat pork and contaminated broth — explicit violations of Levitical food laws (Lev 11:7-8). The practices combine the religiously transgressive (necromancy) with the ritually impure (pork). Together they profile a community that has wholesale abandoned covenant distinctiveness.</p>', '5': "<p>Who say, Stay away — do not come near me, for I am holier than you! The irony: those who commit the most explicit impurities claim superior holiness. The self-designation as holy (<em>qodesh</em>) when they are the farthest from it is the deepest form of religious self-deception. These are smoke in my nostrils, a fire that burns all day — the sensory image of YHWH's sustained displeasure.</p>", '6': "<p>See, it stands written before me: I will not be silent — I will repay; I will pay it fully into their laps. The written-before-me is covenant-legal language: the charges are recorded. YHWH's refusal to be silent (contrast 62:1 where YHWH refuses silence for Zion's sake — here he refuses silence in judgment) grounds the judgment as deliberate and unavoidable.</p>", '7': "<p>Your iniquities and your fathers' iniquities together — the LORD (<em>YHWH</em>, disp 4) declares — because they burned incense on the mountains and reviled me on the hills. The generational guilt: the children inherit the consequences of the fathers' covenant violations. The mountains-and-hills worship is the recurring marker of the Canaanite high places that Israel adopted.</p>", '8': "<p>As new wine is found in a cluster and someone says, Do not destroy it — a blessing is in it — so I will do for the sake of my servants, and not destroy them all. The remnant principle: even in the cluster of bad grapes there is good wine worth preserving. YHWH's judgment is not totalistic; his servants are the living wine hidden in the apostate cluster. The servant/servants distinction: the whole community is addressed, but within it a remnant of faithful servants is preserved.</p>", '9': "<p>I will bring forth from Jacob a people, and from Judah an inheritor of my mountains; my chosen ones shall possess it, and my servants shall dwell there. The chosen-and-servants vocabulary links back to chapters 41-53: the servant who suffered (53) now becomes the community of servants who inherit. The mountains are both the hills of Judah and the eschatological mountain of YHWH's house (2:2-3).</p>", '10': '<p>Sharon shall become a meadow for flocks, and the Valley of Achor a resting place for cattle — for my people who have sought me. The two geographical markers span the width of the promised land: Sharon on the Mediterranean coast, Achor (meaning trouble) in the Jordan Valley. The valley of trouble (Josh 7:24-26, Hos 2:15) becomes a door of hope — a place of rest rather than cursing. The land itself is restored for those who sought YHWH.</p>', '11': '<p>But you who forsake YHWH (<em>YHWH</em>, disp 4) and forget my holy (<em>qodesh</em>, disp 2) mountain, who set a table for Fortune and fill cups of mixed wine for Destiny — the apostate community practices divination-feasting dedicated to Babylonian fortune-gods (Gad and Meni). The specific identification of the gods marks this as Babylonian syncretism from the exile. Forsaking YHWH and forgetting his mountain are the active forms of the passive wandering of v 2.</p>', '12': '<p>I will destine you to the sword, and you will all bow down for slaughter, because when I called you did not answer; when I spoke you did not listen. The judgment is proportional to the rejection: YHWH called (spread his hands, vv 1-2); they did not answer. The refusing-to-answer reverses the covenant dialogue of 55:6-7 — YHWH was near and available; they did not seek him.</p>', '13': '<p>Therefore the Lord GOD declares: My servants shall eat, but you will go hungry; my servants shall drink, but you will be thirsty. The servant-contrast: everything the servants receive (eating, drinking, rejoicing, singing, good names) is the inverse of what the apostates experience (hunger, thirst, shame, crying, wailing, death). The chapter divides humanity into exactly two categories.</p>', '14': '<p>My servants shall shout for joy of heart, but you shall cry out in pain of heart and wail in anguish of spirit (<em>ruach</em>, disp 4). The <em>ruach</em>-anguish of the apostate is the inverted image of the Spirit-joy of the servant (61:1-3). The servant community is characterized by Spirit-life and Spirit-joy; the apostate community is characterized by <em>ruach</em>-anguish — spirit broken, not filled.</p>', '15': "<p>You will leave your name behind as a curse for my chosen ones; and the Lord GOD will put you to death, while his servants will be called by a different name. The name-given (to YHWH's servants) and the name-left-as-a-curse (by the apostates) are parallel to the new-name promise of 62:2 and 65:16. The chosen ones and servants receive a new, blessing-bearing name; the apostates become the vocabulary of cursing.</p>", '16': '<p>Whoever blesses himself in the land will bless himself by the God of faithfulness (<em>emet</em>, truth/faithfulness, disp 2 at 61:8), and whoever takes an oath will swear by the God of faithfulness (<em>elohim</em>, disp 4). The God-of-faithfulness title in vv 15-16 (twice) is unique in the OT. <em>Emet</em> (faithfulness, truth) is what YHWH promised to give at 61:8 — his covenant-dealing is <em>emet</em>. Because the former troubles are forgotten, the God of faithfulness can be the ground of all blessing-speech and oath-taking.</p>', '17': "<p>For see, I am creating new heavens and a new earth; the former things will not be remembered or come to mind. The new creation declaration: the same <em>bara</em> (create) used in Gen 1:1 and Isa 40:28 — YHWH's creative act, not renovation. The forgetting of former things is the eschatological amnesia that makes the new creation a true new beginning, not a continuation. Peter (2 Pet 3:13) and John (Rev 21:1) pick up this promise directly.</p>", '18': "<p>Be glad and rejoice forever in what I am creating; for see, I am creating Jerusalem to be a joy, and her people a delight. The forever-rejoicing is <em>olam</em>-gladness — the same permanent joy of 35:10, 51:11, 61:7. The new creation's center is the new Jerusalem: the city is not merely included in the new creation but is its focal point and the site of its greatest joy.</p>", '19': "<p>I will rejoice in Jerusalem and be glad in my people; no more shall the sound of weeping or the voice of distress be heard in her. The divine rejoicing mirrors the community's rejoicing — YHWH's delight in Zion (62:4-5) is reciprocated by Zion's delight in YHWH. The elimination of weeping and distress is the comprehensive definition of shalom: every form of unraveling is healed.</p>", '20': '<p>Never again will there be an infant who lives only a few days, or an old man who does not complete his years; for the young man who dies at a hundred will be considered a youth, and the one who does not reach a hundred will be considered accursed. The eschatological longevity: infant mortality (the most vivid form of life-cut-short) and premature adult death are both abolished. A hundred years is the measure of an incomplete life — the new creation extends life expectation beyond what any present calculation allows.</p>', '21': "<p>They shall build houses and live in them; they shall plant vineyards and eat their fruit. The covenant-blessing in its most concrete form: the work of one's hands benefits oneself. This reverses the covenant curse of Deut 28:30 (you will build a house but another will live in it; you will plant a vineyard but not harvest it). The new creation restores the full benefit of human labor within covenant.</p>", '22': "<p>They will not build only for others to inhabit; they will not plant only for others to eat — the Deut 28 curse is completely reversed. For like the days of a tree shall the days of my people be, and my chosen ones shall long enjoy the work of their hands. The tree-days life-span: ancient trees (cedar, oak) live for centuries. The chosen ones' lives extend to tree-scale duration — the image of deep-rooted permanence and slow, patient growth into full fruiting.</p>", '23': '<p>They shall not toil for nothing or give birth to children who meet disaster; for they are the offspring of those whom YHWH (<em>YHWH</em>, disp 4) has blessed, and their descendants with them. The generational blessing: the children of the covenant community inherit blessing, not curse. The Deut 28 curses included futile labor and afflicted children; both are reversed. The offspring-of-the-blessed is the Abrahamic vocabulary (Gen 12:2-3) applied to the restored community.</p>', '24': '<p>Before they call, I will answer; while they are still speaking, I will listen. The eschatological acceleration of prayer: YHWH answers before the word is formed. This is the maximum expression of divine attentiveness — the inverse of the lament that YHWH was not responding (63:15-19, 64:12). The silence of YHWH under which the community prayed is replaced by an anticipating presence that meets the prayer before it is voiced.</p>', '25': "<p>The wolf and the lamb will graze together, and the lion will eat straw like the ox; dust will be the serpent's food. They will neither harm nor destroy in all my holy (<em>qodesh</em>, disp 2) mountain, says YHWH (<em>YHWH</em>, disp 4). The restoration of Edenic peace echoes 11:6-9 — the same predator-prey reconciliation marks the final state as a return-to-garden condition. The holy mountain is the place of covenant presence; in it all violence is eliminated. The serpent-eating-dust (Gen 3:14) is not undone but incorporated into the peaceable order — the serpent remains in its cursed state while all others are restored. Rev 21-22 inhabits this vision as the new-Jerusalem image of the final state.</p>"}, '66': {'1': "<p>YHWH opens the closing chapter with a sovereignty claim that destabilizes any human attempt to contain him: Heaven is my throne and the earth is my footstool; where is the house you would build for me, and where is my resting place? The throne-footstool image is the standard iconography of ancient Near Eastern kingship — but YHWH's throne is the cosmos itself. The rhetorical question challenges the temple theology that assumes YHWH needs or is contained by a building. Stephen quotes this verse in his climactic speech (Acts 7:48-50) as the reason Israel's leaders, who killed the prophets and now Jesus, have fundamentally misunderstood YHWH's nature.</p>", '2': "<p>All these things my hand has made, and all these things exist, declares YHWH (<em>YHWH</em>, disp 4). But this is the one I will regard: the humble and contrite in spirit (<em>ruach</em>, disp 4), who trembles at my word. The reversal: YHWH who fills the cosmos looks not for grand structures but for a crushed and humble <em>ruach</em>. The trembling-at-YHWH's-word is the mark of the remnant throughout Isaiah (cf. 57:15; 66:5). The <em>ruach</em>-contrast: YHWH's <em>ruach</em> fills the cosmos; the humble person's <em>ruach</em> is what YHWH inhabits. Ps 51:17 makes the same claim: a broken and contrite heart YHWH will not despise.</p>", '3': "<p>Whoever slaughters an ox is like one who kills a man; whoever sacrifices a lamb is like one who breaks a dog's neck — the shocking equation of orthodox sacrifice with violence. The verse is not condemning all sacrifice but the sacrifice of those whose heart-condition is that of v 3b: who have chosen their own ways and whose <em>nefesh</em> (soul, disp 3) delights in their abominations. Sacrifice without heart-submission is no different from murder and ritual impurity. The heart-posture of v 2 (humble, contrite) is the necessary condition for any worship to be received.</p>", '4': "<p>I in turn will choose what they dread and bring their fears upon them, because when I called no one answered; when I spoke they did not listen. The answering-calling pattern again: YHWH called (65:1-2, 12), they did not answer — therefore YHWH sends them what they most feared. The judgment is judicial and proportional: their rejection of YHWH's call results in experiencing the fears they generated for themselves by their choices.</p>", '5': "<p>Hear the word of YHWH (<em>YHWH</em>, disp 4), you who tremble at his word: Your brothers who hate you and reject you for my name's sake have said, Let YHWH (<em>YHWH</em>, disp 4) be glorified, that we may see your joy — but they shall be put to shame. The community of those who tremble at YHWH's word (v 2) is being persecuted by those who mock their trust in YHWH — saying sarcastically that they are waiting to see if YHWH will vindicate them. The answer: the mockers will be put to shame, and the trembling community will see the city's joy (v 10).</p>", '6': "<p>Listen — an uproar from the city, a voice from the temple, the voice of YHWH (<em>YHWH</em>, disp 4) repaying his enemies what they deserve. The voice of YHWH from the temple is the covenant-judgment sound (Ps 29; Joel 3:16; Amos 1:2). The repaying of enemies is the reversal of the exile's humiliation and the answer to the prayer of 63:15-64:12. The temple, once destroyed (64:11), is now the source of YHWH's victorious voice.</p>", '7': "<p>Before she went into labor she gave birth; before her pain came on her, she delivered a son. The instantaneous birth — without labor — reverses the normal order. The birth of the new community is YHWH's miraculous act: no human effort, no natural process, no suffering required on Zion's part. The son born in an instant is the community of the new creation, born in the moment of divine decision.</p>", '8': "<p>Who has heard of such a thing? Who has seen things like these? Can a land be delivered in a single day? Can a nation be born in an instant? For as soon as Zion was in labor, she gave birth to her children. The rhetorical impossibility-questions frame the event as miracle. The single-day nation-birth is the maximum form of YHWH's creative sovereignty: what took generations in the exodus-settlement takes one day in the new exodus.</p>", '9': "<p>Would I bring to the point of birth and not cause delivery? says YHWH (<em>YHWH</em>, disp 4); Would I, who give birth, then close the womb? says your God (<em>elohim</em>, disp 4). The divine rhetorical question uses the midwife/mother image: YHWH has begun the process (brought to birth) and will complete it (not close the womb). The promise is grounded in the logic of YHWH's own purposes: he does not begin what he does not finish. This is the same assurance as 55:11 (my word will not return to me empty).</p>", '10': "<p>Rejoice with Jerusalem and be glad for her, all you who love her; rejoice with her in her joy, all you who mourn over her. The call to communal rejoicing extends to all who have mourned for Jerusalem — including those who mourn in exile. The mourning-turned-joy pattern is the same as 61:3 (garment of praise instead of faint spirit). The community of mourners becomes the community of rejoicing by YHWH's act alone.</p>", '11': "<p>So that you may nurse and be satisfied at her comforting breasts; so that you may drink deeply and delight in her abundant glory (<em>kabod</em>, disp 2). The nursing-Jerusalem image: the city herself nourishes her children. The <em>kabod</em> (glory) of Jerusalem is itself nourishing — the community draws life from YHWH's glory-presence in the city. The abundance (<em>zizon</em>) of her glory suggests overflowing wealth that more than suffices.</p>", '12': '<p>For thus says YHWH (<em>YHWH</em>, disp 4): I will extend prosperity (<em>shalom</em>, disp 2) to her like a river, and the wealth of nations like a flooding stream; and you will nurse, you will be carried on her hip, and bounced on her knees. The <em>shalom</em> extended like a river: the comprehensive wellbeing flows without ceasing, like the river of the new Jerusalem (Rev 22:1). The nursing-carried-bounced images: the restored community is treated as an infant by YHWH and by Jerusalem — completely provided for, completely secure, completely delighted in.</p>', '13': '<p>As a mother comforts her child, so I will comfort you; and you will be comforted in Jerusalem. The comfort promised in 40:1 — comfort, comfort my people — reaches its fulfillment here. YHWH as mother-comforter is the culmination of the nursing/carrying images that began at 40:11 (shepherd carrying lambs). The comfort is located specifically in Jerusalem: the city and the divine presence are inseparable in the new creation.</p>', '14': "<p>When you see this, your heart will rejoice and your bones will flourish like the grass; the hand of YHWH (<em>YHWH</em>, disp 4) will be made known (<em>yada</em>, disp 2) to his servants, and his fury to his enemies. The physical flourishing (bones like grass) is the embodied form of the inner rejoicing — wholeness reaches the body. The knowing of YHWH's hand by the servants is the final form of the exodus-knowledge: YHWH revealed his character in the exodus; he reveals it again in the new creation's deliverance. The enemies experience the same divine power as fury rather than grace.</p>", '15': "<p>For see, YHWH (<em>YHWH</em>, disp 4) will come in fire, with his chariots like a whirlwind, to repay his anger in fury and his rebuke with flames of fire. The warrior-theophany closes the book as it opened the restoration-section (63:1-6). The fire-chariot-whirlwind is Elijah's pattern (2 Kgs 2:11) and Ezekiel's chariot-vision (Ezek 1). YHWH's coming for judgment is as real and physical as his coming for restoration.</p>", '16': '<p>For by fire and by his sword YHWH (<em>YHWH</em>, disp 4) will execute judgment (<em>shaphat</em>, disp 2) upon all flesh, and the slain of YHWH (<em>YHWH</em>, disp 4) shall be many. The judgment (<em>shaphat</em>) is comprehensive — all flesh — and lethal. The courtroom-judgment vocabulary (<em>shaphat</em>) is applied to cosmic warfare: YHWH both judges and executes. The many slain is the reverse of the many made righteous in 53:11-12.</p>', '17': "<p>Those who consecrate and purify themselves to enter the gardens, following the one in their midst, eating pig and abominable things and mice — they shall come to an end together, declares YHWH (<em>YHWH</em>, disp 4). The garden-cult practitioners of 65:3-4 reappear here for their final judgment. Their ritual self-purification for abominable worship is the ultimate religious inversion — the language of <em>qodesh</em> used for what is <em>tame</em> (impure). YHWH's <em>qodesh</em>/holy (disp 2) designation is reserved for those who tremble at his word (v 2, 5), not for those who consecrate themselves to idolatry.</p>", '18': "<p>For I know their works and their thoughts, and the time is coming to gather all nations and peoples of every language; they will come and see my glory (<em>kabod</em>, disp 2). The gathering of all nations to see YHWH's <em>kabod</em> is the universal scope of the whole book's vision: from the nations gathering against Zion (chapters 1-12) to the nations streaming to Zion's light (chapters 40-66). The <em>kabod</em> they will see is the same glory that filled the temple (6:3) — YHWH's sovereign, holy beauty displayed to all.</p>", '19': '<p>I will set a sign among them, and from them I will send survivors to the nations — to Tarshish, Pul, Lud who draw the bow, Tubal and Javan, to the far coastlands that have not heard my fame or seen my glory (<em>kabod</em>, disp 2). The survivors are sent as missionaries: those who saw the <em>kabod</em> go out to declare it to those who have not. The sending-pattern is the Isaianic servant-pattern applied now to the whole restored community (49:6: a light to the nations). The listing of specific distant nations emphasizes the genuinely universal scope.</p>', '20': "<p>They shall bring all your brothers from all the nations as an offering to YHWH (<em>YHWH</em>, disp 4) — riding on horses, in chariots and litters, on mules and camels — to my holy (<em>qodesh</em>, disp 2) mountain Jerusalem, says YHWH (<em>YHWH</em>, disp 4), as the people of Israel bring their grain offering in clean vessels to the house of YHWH (<em>YHWH</em>, disp 4). The exiled brothers are brought back as an offering — the community's return to the holy mountain is itself a liturgical act. The nations who bring them are functioning as priests of the offering. The <em>qodesh</em>/holy mountain is the destination toward which the whole book has been moving.</p>", '21': '<p>And from among them I will also take some as priests and Levites, says YHWH (<em>YHWH</em>, disp 4). From among the gathered nations YHWH takes priests and Levites — the most radical universalism: the priestly office, reserved for one tribe, is opened to those outside Israel entirely. This fulfills 61:6 (you will be called priests of YHWH) applied now to the previously excluded nations. Rev 1:6 and 5:10 apply this promise to the church — made priests to serve YHWH.</p>', '22': '<p>For as the new heavens and the new earth that I am making shall endure before me, declares YHWH (<em>YHWH</em>, disp 4), so shall your offspring and your name endure. The durability of the new creation guarantees the durability of the community: the same <em>olam</em>-permanence of the cosmos is the <em>olam</em>-permanence of the covenant people. Name and offspring — identity and continuity — are as permanent as the new heavens and earth.</p>', '23': "<p>From one new moon to the next, and from one Sabbath to the next, all people shall come and worship before me, declares YHWH (<em>YHWH</em>, disp 4). The liturgical calendar (new moon, Sabbath) continues in the new creation, but now all flesh participates — the calendar that structured Israel's covenant time becomes the calendar of universal worship. The weekly and monthly rhythms of creation (Gen 1:14) become the rhythms of eschatological worship: creation and new creation are unified in the praise of YHWH.</p>", '24': "<p>And they shall go out and look at the corpses of those who rebelled against me, for their worm shall not die, and their fire shall not be quenched, and they shall be an abhorrence to all flesh. The book closes with the most severe image in the entire corpus: the permanent judgment of the rebels, visible as a perpetual warning from the new Jerusalem. The undying worm and unquenched fire are quoted by Jesus in Mark 9:44-48 as the description of Gehenna. The final word of Isaiah is not comfort but judgment — the book does not end with the new creation alone but with the contrast between those who worship YHWH in the new creation and those whose rebellion made them an abhorrence. The whole book's trajectory — YHWH's holiness judging and redeeming — ends with both dimensions fully in view.</p>"}}

def main():
    data = load_comm('mkt-original', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah original: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-original', 'isaiah', data)

if __name__ == '__main__':
    main()
